local HttpService=game:GetService("HttpService")
local root=workspace:FindFirstChild("PunchWallRPG")
local result={concrete=0,asphalt=0,metal=0,scripts=0}
for _,d in ipairs(root:GetDescendants()) do if d:IsA("BasePart") then if d.MaterialVariant=="KaijuDamagedConcrete" then result.concrete+=1 elseif d.MaterialVariant=="KaijuWornAsphalt" then result.asphalt+=1 elseif d.MaterialVariant=="KaijuContainmentMetal" then result.metal+=1 end elseif d:IsA("LuaSourceContainer") then result.scripts+=1 end end
return HttpService:JSONEncode(result)
